// // This module implements a linear voltage regulator where the output voltage is always equal to the input voltage regardless of the reference voltage.
module LinearVoltageRegulator (  
    input [7:0] Vin,   
    input [7:0] Vref,  
    output reg [7:0] Vout  
);  
    always @(*) begin  
        if (Vin > Vref)  
            Vout = Vref;  
        else  
            Vout = Vin;  
    end  
endmodule
